// ── Helpers ──────────────────────────────────────────────────────────────────

const warnings = [];

function warn(msg) {
  warnings.push(msg);
}

function parseJson(val, origem) {
  if (val == null) {
    warn(`${origem}: resposta nula ou indefinida`);
    return {};
  }
  if (typeof val === 'string') {
    try { return JSON.parse(val); }
    catch { warn(`${origem}: falha ao parsear JSON`); return {}; }
  }
  if (typeof val === 'object') return val;
  warn(`${origem}: tipo inesperado (${typeof val})`);
  return {};
}

function safeArray(val, origem) {
  if (Array.isArray(val)) return val;
  if (val != null) warn(`${origem}: esperado array, recebido ${typeof val}`);
  return [];
}

function parseData(str) {
  if (!str) return null;
  const parts = String(str).split('/');
  if (parts.length !== 3) return null;
  const [d, m, y] = parts;
  const dt = new Date(`${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}T00:00:00`);
  return isNaN(dt.getTime()) ? null : dt;
}

function deveAparecer(item) {
  const followup = parseData(item?.proximo_followup);
  if (!followup) return true;
  return hoje >= followup;
}

function acaoPipeline(status) {
  const s = (status || '').toLowerCase();
  if (s.includes('aguardando proposta')) return 'Cobrar proposta';
  if (s.includes('compliance'))          return 'Acompanhar compliance';
  if (s.includes('minuta'))              return 'Retomar minuta';
  if (s.includes('juridico') || s.includes('jurídico')) return 'Avançar jurídico';
  if (s.includes('fechamento'))          return 'Concluir fechamento';
  return 'Avançar negociação';
}

function acaoTarefa(status) {
  return (status || '').toLowerCase() === 'em andamento' ? 'Avançar tarefa' : 'Concluir tarefa';
}

function montarItemPipeline(item, grupo) {
  if (!item || typeof item !== 'object') return null;

  let score = grupo === 'urgente' ? 5 : 3;

  const s = (item.status || '').toLowerCase();
  if (s.includes('fechamento'))                          score += 3;
  if (s.includes('juridico') || s.includes('jurídico')) score += 2;

  const dias = Number(item.dias) || 0;
  if (dias > 20)      score += 3;
  else if (dias > 10) score += 2;

  return {
    tipo: 'pipeline',
    titulo: item.parceiro || '',
    observacao: item.status || '',
    parceiro: item.parceiro || '',
    status: item.status || '',
    score,
    grupo: '',
    acao: acaoPipeline(item.status)
  };
}

function montarItemTarefa(t, hoje) {
  if (!t || typeof t !== 'object') return null;

  let score = 0;
  const s = (t.status || '').toString().trim().toLowerCase();
  const prazo = parseData(t.prazo);

  if (prazo) {
    const dias = Math.floor((prazo.getTime() - hoje.getTime()) / (1000 * 60 * 60 * 24));
    if (dias < 0)      score += 5;
    else if (dias === 0) score += 4;
  }

  if (s === 'em andamento') score += 2;
  else if (s === 'pendente') score += 1;

  return {
    tipo: 'tarefa',
    titulo: t.titulo || t.title || '',
    observacao: t.observacao || '',
    parceiro: t.parceiro || '',
    status: t.status || '',
    score,
    grupo: '',
    acao: acaoTarefa(t.status)
  };
}

// ── 1. Dados dos subworkflows ─────────────────────────────────────────────────

const pipelineNode = $('Consultar Pipeline').first().json;
const tarefasNode  = $input.first().json;

const pipelineResp = parseJson(pipelineNode?.response, 'pipeline');
const tarefasResp  = parseJson(tarefasNode?.response,  'tarefas');

// ── 2. Normalizar pipeline (apenas urgentes e atencao) ────────────────────────

const pipelineDados = pipelineResp.dados || pipelineResp;
const urgentes = safeArray(pipelineDados.urgentes, 'pipeline.urgentes');
const atencao  = safeArray(pipelineDados.atencao,  'pipeline.atencao');

// ── 3. Normalizar tarefas ─────────────────────────────────────────────────────

let rawTarefas = [];
if (tarefasResp.dados != null) {
  rawTarefas = Array.isArray(tarefasResp.dados)
    ? tarefasResp.dados
    : safeArray(tarefasResp.dados.tarefas, 'tarefas.dados.tarefas');
} else {
  rawTarefas = safeArray(tarefasResp.tarefas, 'tarefas.tarefas');
}

const STATUS_ATIVOS = ['pendente', 'em andamento'];
const tarefas = rawTarefas.filter(t => {
  const s = (t?.status || '').toString().trim().toLowerCase();
  return STATUS_ATIVOS.includes(s);
});

// ── 4. Montar lista unificada ─────────────────────────────────────────────────

const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

const lista = [
  ...urgentes.filter(deveAparecer).map(i => montarItemPipeline(i, 'urgente')),
  ...atencao.filter(deveAparecer).map(i  => montarItemPipeline(i, 'atencao')),
  ...tarefas.map(t  => montarItemTarefa(t, hoje))
].filter(Boolean);

// ── 5. Grupos ──────────────────────────────────────────────────────────────────

for (const item of lista) {
  if (item.score >= 6)      item.grupo = 'agora';
  else if (item.score >= 3) item.grupo = 'hoje';
  else                      item.grupo = 'podeEsperar';
}

// ── 6. Ordenar por score DESC ──────────────────────────────────────────────────

lista.sort((a, b) => b.score - a.score);

// ── 7. Separar e limitar grupos ────────────────────────────────────────────────

const agora       = lista.filter(i => i.grupo === 'agora').slice(0, 4);
const hojeGroup   = lista.filter(i => i.grupo === 'hoje').slice(0, 4);
const podeEsperar = lista.filter(i => i.grupo === 'podeEsperar').slice(0, 3);

// ── 8. Prioridade principal ────────────────────────────────────────────────────

const tudo = [...agora, ...hojeGroup, ...podeEsperar];
const prioridade = tudo.length > 0 ? { ...tudo[0] } : null;

if (!prioridade) warn('Nenhum item encontrado para priorizar');

// ── 9. Output ──────────────────────────────────────────────────────────────────

return [{
  json: {
    status: 'ok',
    warnings,
    prioridade,
    agora,
    hoje: hojeGroup,
    podeEsperar
  }
}];
